import React, { useState } from 'react';
import { Bot, CalendarDays, Database, Play, Trash2, Plus, LayoutDashboard } from 'lucide-react';

export default function App() {
  const [activeTab, setActiveTab] = useState('fcst');
  const [state, setState] = useState({
    lineMap: { 'T1': 'SEC-T1(USA)', 'P1D': 'SEC-P1(D)(KR)', 'P1F': 'SEC-P1(F)(KR)', 'P2D': 'SEC-P2(D)(KR)', 'P2F': 'SEC-P2(F)(KR)', 'P3F': 'SEC-P3(F)(KR)', 'P4D': 'SEC-P4(D)(KR)', 'P4H': 'SEC-P4(H)(KR)', 'X2': 'SEC-X2L(CN)' },
    atmMaster: [
      { id: 'ATM-102', start: '2026-01-13', end: '2026-01-29', maxCapa: 6 },
      { id: 'ATM-105', start: '2026-02-10', end: '2026-02-28', maxCapa: 6 },
      { id: 'ATM-112', start: '2026-03-12', end: '2026-03-29', maxCapa: 6 },
      { id: 'ATM-115', start: '2026-04-10', end: '2026-04-28', maxCapa: 6 },
      { id: 'ATM-119', start: '2026-05-12', end: '2026-05-28', maxCapa: 6 },
      { id: 'ATM-122', start: '2026-07-12', end: '2026-07-28', maxCapa: 6 },
      { id: 'ATM-125', start: '2026-08-05', end: '2026-08-24', maxCapa: 6 },
      { id: 'ATM-129', start: '2026-09-09', end: '2026-09-29', maxCapa: 6 },
      { id: 'ATM-132', start: '2026-10-11', end: '2026-10-27', maxCapa: 6 },
      { id: 'ATM-135', start: '2026-11-04', end: '2026-11-22', maxCapa: 6 }
    ]
  });

  const removeAtmRule = (id) => {
    setState(prev => ({ ...prev, atmMaster: prev.atmMaster.filter(a => a.id !== id) }));
  };

  return (
    <div className="flex h-screen bg-gray-100">
      <aside className="w-64 bg-slate-900 text-white p-6">
        <h1 className="text-xl font-bold mb-8 flex items-center"><Bot className="mr-2 text-blue-400"/> PSK Portal</h1>
        <button onClick={() => setActiveTab('fcst')} className="w-full text-left p-3 hover:bg-slate-700 rounded mb-2">FCST 스케줄러</button>
        <button onClick={() => setActiveTab('master')} className="w-full text-left p-3 hover:bg-slate-700 rounded">마스터 데이터 관리</button>
      </aside>

      <main className="flex-1 p-8 overflow-y-auto">
        {activeTab === 'fcst' ? (
          <div className="bg-white p-6 rounded shadow">
            <h2 className="text-xl font-bold mb-4">FCST 스케줄링</h2>
            <textarea className="w-full h-64 border p-2 mb-4" placeholder="데이터를 붙여넣으세요..."></textarea>
            <button className="bg-blue-600 text-white px-6 py-2 rounded">자동 배정 시작</button>
          </div>
        ) : (
          <div className="bg-white p-6 rounded shadow">
            <h2 className="text-xl font-bold mb-6">ATM 마스터 데이터</h2>
            <table className="w-full border text-left">
              <thead className="bg-gray-50"><tr><th className="p-2 border">ID</th><th className="p-2 border">시작일</th><th className="p-2 border">종료일</th><th className="p-2 border">Capa</th><th className="p-2 border">삭제</th></tr></thead>
              <tbody>
                {state.atmMaster.map(a => (
                  <tr key={a.id}>
                    <td className="p-2 border">{a.id}</td><td className="p-2 border">{a.start}</td><td className="p-2 border">{a.end}</td><td className="p-2 border">{a.maxCapa}</td>
                    <td className="p-2 border"><button onClick={() => removeAtmRule(a.id)} className="text-red-500"><Trash2 size={18}/></button></td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </main>
    </div>
  );
}
